  	import com.google.gson.Gson;  
  	import com.google.gson.GsonBuilder;  
  	import org.json.JSONArray;
  	import org.json.JSONException;
  	import org.json.JSONObject;
  	import sailpoint.object.Application;
  	import sailpoint.connector.webservices.WebServicesClient;
  	import org.apache.commons.logging.Log;
  	import org.apache.commons.logging.LogFactory;
  
  	Log logger = LogFactory.getLog("org.ascension.sailpoint.rules.mdstaff.aggregation.afterrule");
  	
  	String MDSTAFF_APPLICATION_NAME="MDStaff - Ascension" ;
  	
  	int PAGE_SIZE = 2000 ;  
  	int MAX_NUMBER_OF_PAGES = 10 ; 
  		
	String currentAccessToken = "" ;
  	String webServiceBaseURL = "" ;
  	String mdStaffInstanceName = "" ;
  		
	int totalNumberOfProvidersFetched = 0 ;
	
	Map providerInfoMap = new HashMap(); 
	
	void getApplicationDetails(){
		
		logger.trace("Ascension-Rule-MDStaff-Ascension-After - getApplicationDetails() - End.") ;
		
		try{
		  	
		  	Application appObj = context.getObjectByName(Application.class,MDSTAFF_APPLICATION_NAME);
		  	webServiceBaseURL = appObj.getAttributeValue("genericWebServiceBaseUrl");
		  	mdStaffInstanceName = appObj.getAttributeValue("mdStaff-InstanceName");		
		
		} catch (Exception exception){
			
			logger.error("Ascension-Rule-MDStaff-Ascension-After - getApplicationDetails() - Error getting application details") ;
			
			logger.trace(exception.printStackTrace());
		}
		
		logger.trace("Ascension-Rule-MDStaff-Ascension-After - getApplicationDetails() - End.") ;	
	}
	
	void getAccessToken(){
		
		logger.trace("Ascension-Rule-MDStaff-Ascension-After - getAccessToken() - End.") ;
		
		try{
		  	
			currentAccessToken = getLatestAccessToken(restClient);		
		
		} catch (Exception exception){
			
			logger.error("Ascension-Rule-MDStaff-Ascension-After - getAccessToken() - Error getting access token") ;
			
			logger.trace(exception.printStackTrace());
		}
		
		logger.trace("Ascension-Rule-MDStaff-Ascension-After - getAccessToken() - End.") ;	
	}
	
	public String fetchProviderRecords(int pageNumber){
		
		logger.trace("Ascension-Rule-MDStaff-Ascension-After - fetchProviderRecords() - Start...") ;
		
		String statusMessage = "" ;
		
		getAccessToken() ; 
		
		if(currentAccessToken!=null && !currentAccessToken.isEmpty()){
		
		  	Set providerIdSet = new HashSet();
		  	
		  	List allowedStatuses = new ArrayList();
		  	allowedStatuses.add("200");
		
		  	Map payLoadMap = new HashMap();
		  	Map headersMap = new HashMap();
		
		  	headersMap.put("Content-Type","application/json");
		  	headersMap.put("Accept","application/json");
		  	headersMap.put("Authorization","Bearer "+currentAccessToken);
	 			  	
			//This payload is for testing only. We can specify limited results for aggregation and testing
		  	//String payload = "{\"source\":\"Appointment\",\"fields\": [\"ProviderID\",\"Provider.NPI\",\"Provider.FirstName\",\"Provider.MiddleName\",\"Provider.LastName\",\"Provider.SpecialtyID_1.Description\",\"Provider.SpecialtyID_2.Description\",\"Provider.SpecialtyID_3.Description\",\"Provider.SpecialtyID_4.Description\",\"FacilityID.Name\",\"MinistryAssociation.Code\",\"PrimaryAddressID.city\", \"PrimaryAddressID.state\", \"PrimaryAddressID.zip\", \"PrimaryAddressID.address\", \"PrimaryAddressID.address2\", \"PrimaryAddressID.location\", \"PrimaryAddressID.startDate\", \"PrimaryAddressID.endDate\", \"PrimaryAddressID.telephone\", \"PrimaryAddressID.fax\",\"SecondaryAddressID.city\", \"SecondaryAddressID.state\", \"SecondaryAddressID.zip\", \"SecondaryAddressID.address\", \"SecondaryAddressID.address2\", \"SecondaryAddressID.location\", \"SecondaryAddressID.startDate\", \"SecondaryAddressID.endDate\", \"SecondaryAddressID.telephone\", \"SecondaryAddressID.fax\",\"IDNumber\",\"Provider.FieldOfLicensureID.Description\",\"StatusID.Description\",\"Provider.SSN\",\"Provider.BirthDate\"],\"filter\": {\"Archived\": \"false\",\"MinistryAssociation.Code\": [\"MIKAL\",\"MIGRA\",\"MIDET\",\"MISAG\",\"MIROC\",\"ININD\",\"INEVA\"]},\"settings\": {\"IncludeArchivedProviders\": \"false\",\"IncludeApplicants\": \"false\"},\"resultsperpage\": 0,\"page\": 1}";
		  
		
		  	//This payload fetches all available providers matching the criteria.
		  	//String payload = "{\"source\":\"Appointment\",\"fields\": [\"ProviderID\",\"Provider.NPI\",\"Provider.FirstName\",\"Provider.MiddleName\",\"Provider.LastName\",\"Provider.SpecialtyID_1.Description\",\"Provider.SpecialtyID_2.Description\",\"Provider.SpecialtyID_3.Description\",\"Provider.SpecialtyID_4.Description\",\"FacilityID.Name\",\"MinistryAssociation.Code\",\"PrimaryAddressID.city\", \"PrimaryAddressID.state\", \"PrimaryAddressID.zip\", \"PrimaryAddressID.address\", \"PrimaryAddressID.address2\", \"PrimaryAddressID.location\", \"PrimaryAddressID.startDate\", \"PrimaryAddressID.endDate\", \"PrimaryAddressID.telephone\", \"PrimaryAddressID.fax\",\"SecondaryAddressID.city\", \"SecondaryAddressID.state\", \"SecondaryAddressID.zip\", \"SecondaryAddressID.address\", \"SecondaryAddressID.address2\", \"SecondaryAddressID.location\", \"SecondaryAddressID.startDate\", \"SecondaryAddressID.endDate\", \"SecondaryAddressID.telephone\", \"SecondaryAddressID.fax\",\"IDNumber\",\"Provider.FieldOfLicensureID.Description\",\"StatusID.Description\",\"Provider.SSN\",\"Provider.BirthDate\"],\"filter\": {\"Archived\": \"false\",\"MinistryAssociation.Code\": [\"MIKAL\",\"MIGRA\",\"MIDET\",\"MISAG\",\"MIROC\",\"ININD\",\"INEVA\"]},\"settings\": {\"IncludeArchivedProviders\": \"false\",\"IncludeApplicants\": \"false\"}}";
		
		  	String payload = "{\"source\":\"Appointment\",\"fields\": [\"ProviderID\",\"Provider.NPI\",\"Provider.FirstName\",\"Provider.MiddleName\",\"Provider.LastName\",\"Provider.SpecialtyID_1.Description\",\"Provider.SpecialtyID_2.Description\",\"Provider.SpecialtyID_3.Description\",\"Provider.SpecialtyID_4.Description\",\"FacilityID.Name\",\"MinistryAssociation.Code\",\"PrimaryAddressID.city\", \"PrimaryAddressID.state\", \"PrimaryAddressID.zip\", \"PrimaryAddressID.address\", \"PrimaryAddressID.address2\", \"PrimaryAddressID.location\", \"PrimaryAddressID.startDate\", \"PrimaryAddressID.endDate\", \"PrimaryAddressID.telephone\", \"PrimaryAddressID.fax\",\"SecondaryAddressID.city\", \"SecondaryAddressID.state\", \"SecondaryAddressID.zip\", \"SecondaryAddressID.address\", \"SecondaryAddressID.address2\", \"SecondaryAddressID.location\", \"SecondaryAddressID.startDate\", \"SecondaryAddressID.endDate\", \"SecondaryAddressID.telephone\", \"SecondaryAddressID.fax\",\"IDNumber\",\"Provider.FieldOfLicensureID.Description\",\"StatusID.Description\",\"Provider.SSN\",\"Provider.BirthDate\"],\"filter\": {\"Archived\": \"false\",\"MinistryAssociation.Code\": [\"TNNAS\"]},\"settings\": {\"IncludeArchivedProviders\": \"false\",\"IncludeApplicants\": \"false\"}, \"resultsperpage\":"+PAGE_SIZE+",\"page\":"+pageNumber+"}";
		
			logger.info("Ascension-Rule-MDStaff-Ascension-After - fetchProviderRecords() - Payload - " + payload) ;
			 
		  	boolean providersProcessed = false;
		  
		  	String jsonResponse = null;
			Map outputMap = null;
			
		  	try{
				
				jsonResponse  = restClient.executePost(webServiceBaseURL+"/api/"+mdStaffInstanceName+"/query",payload,headersMap,allowedStatuses,false);
		        
		        // logger.debug(jsonResponse) ;
		        
		        if (Util.isNotNullOrEmpty(jsonResponse)) {	 
	        		
	        		jsonResponse = "{\"plist\":"+jsonResponse+"}";
	        		JSONObject json= new JSONObject(jsonResponse);
	        		JSONArray arry = (JSONArray) json.get("plist");
					
					int totalNumberOfRecordsFetched = arry.length(); 
					
					logger.info("Ascension-Rule-MDStaff-Ascension-After - fetchProviderRecords() - totalNumberOfRecordsFetched - " + totalNumberOfRecordsFetched) ;
					
					totalNumberOfProvidersFetched = totalNumberOfProvidersFetched + totalNumberOfRecordsFetched;
					
					if(totalNumberOfRecordsFetched < PAGE_SIZE){
						
						statusMessage = "LAST_PAGE" ;
						 
					} 
					
		            for(int i=0;i<arry.length();i++) {
		            
		               Gson gson = new GsonBuilder().create();  
		
		               Map proMap = gson.fromJson(arry.get(i).toString(), HashMap.class);  
		
		               String pid = proMap.get("ProviderID");
		               String npi = proMap.get("Provider_NPI");
		               String ministryCode = proMap.get("MinistryAssociation_Code");
		               String firstName = proMap.get("Provider_FirstName");
		               String middleName = proMap.get("Provider_MiddleName");
		               String lastName = proMap.get("Provider_LastName");
		               String specialty1 = proMap.get("Provider_SpecialtyID_1_Description");
		               String specialty2 = proMap.get("Provider_SpecialtyID_2_Description");
		               String specialty3 = proMap.get("Provider_SpecialtyID_3_Description");
		               String specialty4 = proMap.get("Provider_SpecialtyID_4_Description");
		               String facilityName = proMap.get("FacilityID_Name");
		              
		               String primary_city = proMap.get("PrimaryAddressID_city");
		               String primary_state = proMap.get("PrimaryAddressID_state");
		               String primary_address1 = proMap.get("PrimaryAddressID_address");
		               String primary_address2 = proMap.get("PrimaryAddressID_address2");
		               String primary_zipCode = proMap.get("PrimaryAddressID_zip");
		               String primary_telephone = proMap.get("PrimaryAddressID_telephone");
		               String primary_fax = proMap.get("PrimaryAddressID_fax");
		               String primary_location = proMap.get("PrimaryAddressID_location");
		               String primary_startDate = proMap.get("PrimaryAddressID_startDate");
		               String primary_endDate = proMap.get("PrimaryAddressID_endDate");
		              
		               String secondary_city = proMap.get("SecondaryAddressID_city");
		               String secondary_state = proMap.get("SecondaryAddressID_state");
		               String secondary_address1 = proMap.get("SecondaryAddressID_address");
		               String secondary_address2 = proMap.get("SecondaryAddressID_address2");
		               String secondary_zipCode = proMap.get("SecondaryAddressID_zip");
		               String secondary_telephone = proMap.get("SecondaryAddressID_telephone");
		               String secondary_fax = proMap.get("SecondaryAddressID_fax");
		               String secondary_location = proMap.get("SecondaryAddressID_location");
		               String secondary_startDate = proMap.get("SecondaryAddressID_startDate");
		               String secondary_endDate = proMap.get("SecondaryAddressID_endDate");
		               
		               String idNumber = proMap.get("IDNumber");
		               String title = proMap.get("Provider_FieldOfLicensureID_Description");
		               String status = proMap.get("StatusID_Description");
		              
		               String maskedSSN = proMap.get("Provider_SSN");
		               if(null!=maskedSSN && !maskedSSN.isEmpty())
		               {
		                 if(maskedSSN.contains("XXX-XX-"))
		                 {
		                 	maskedSSN = maskedSSN.replace("XXX-XX-","");
		                 }
		               }
		               String dob = proMap.get("Provider_BirthDate");
		               if(null!=dob && !dob.isEmpty())
		               {
		                 dob = formatDate(dob);
		               }
		               		
		
		               if (Util.isNotNullOrEmpty(pid)) 
		               {
		                 providerIdSet.add(pid.trim());
		                 outputMap = new HashMap();
		                 outputMap.put("ProviderID",pid.trim());
		                 outputMap.put("NPI",npi);
		                 outputMap.put("Ministry_Domain",ministryCode);
		                 outputMap.put("FirstName",firstName);
		                 outputMap.put("MiddleName",middleName);
		                 outputMap.put("LastName",lastName);
		                 outputMap.put("Specialty1",specialty1);
		                 outputMap.put("Specialty2",specialty2);
		                 outputMap.put("Specialty3",specialty3);
		                 outputMap.put("Specialty4",specialty4);
		                 outputMap.put("FacilityName",facilityName);
		
		                 outputMap.put("PrimaryAddress_OfficeState",primary_state);
		                 outputMap.put("PrimaryAddress_OfficeCity",primary_city);
		                 outputMap.put("PrimaryAddress_OfficeAddress1",primary_address1);
		                 outputMap.put("PrimaryAddress_OfficeAddress2",primary_address2);
		                 outputMap.put("PrimaryAddress_OfficeZipCode",primary_zipCode);
		                 outputMap.put("PrimaryAddress_OfficeTelephone",primary_telephone);
		                 outputMap.put("PrimaryAddress_OfficeFax",primary_fax);
		                 outputMap.put("PrimaryAddress_Location",primary_location);
		                 outputMap.put("PrimaryAddress_StartDate",primary_startDate);
		                 outputMap.put("PrimaryAddress_EndDate",primary_endDate);
		                 
		                 outputMap.put("SecondaryAddress_OfficeState",secondary_state);
		                 outputMap.put("SecondaryAddress_OfficeCity",secondary_city);
		                 outputMap.put("SecondaryAddress_OfficeAddress1",secondary_address1);
		                 outputMap.put("SecondaryAddress_OfficeAddress2",secondary_address2);
		                 outputMap.put("SecondaryAddress_OfficeZipCode",secondary_zipCode);
		                 outputMap.put("SecondaryAddress_OfficeTelephone",secondary_telephone);
		                 outputMap.put("SecondaryAddress_OfficeFax",secondary_fax);
		                 outputMap.put("SecondaryAddress_Location",secondary_location);
		                 outputMap.put("SecondaryAddress_StartDate",secondary_startDate);
		                 outputMap.put("SecondaryAddress_EndDate",secondary_endDate);
		                 outputMap.put("IDNumber",idNumber);
		                 outputMap.put("Title",title);
		                 outputMap.put("Status",status);
		                 outputMap.put("MaskedSSN",maskedSSN);
		                 outputMap.put("BirthDate",dob);
		                 
		                 providerInfoMap.put(pid.trim(),outputMap);
		               }
		             }
		         }
		         providersProcessed = true;
			      } 
			      catch(Exception e) 
			      {
			        logger.error("Ascension-Rule-MDStaff-Ascension-After - fetchProviderRecords() - Error occured while fetching providers - \n"+e.getMessage()); 
			        
			        logger.error(e) ;
			                
			        providersProcessed = false;
			        
			        statusMessage = "ERROR" ;
			      }		
			      	         
		         if(providersProcessed)
		 		  {
		     		String credPayload = null;
		     		String jsonResponse = null;
		     		
		     		headersMap.put("Authorization","Bearer "+currentAccessToken);
		  
		     		int count = 0;
		     		try
		    	  {
		       		credPayload = "{\"source\":\"Credential\",\"fields\":[\"LicenseNumber\",\"LicenseTypeID.Code\",\"ProviderID\"],\"filter\":{\"InUse\":\"true\",\"LicenseTypeID.Code\":[\"DEA\",\"StateProfLicense\"]},\"settings\": {\"IncludeArchivedProviders\": false,\"IncludeApplicants\": false}}";
		       		jsonResponse  = restClient.executePost(webServiceBaseURL+"/api/"+mdStaffInstanceName+"/query",credPayload,headersMap,allowedStatuses,false);
		        	if (Util.isNotNullOrEmpty(jsonResponse)) 
		        	{	 
		        		jsonResponse = "{\"plist\":"+jsonResponse+"}";
		        		JSONObject json= new JSONObject(jsonResponse);
		        		JSONArray arry = (JSONArray) json.get("plist");
		
		            for(int i=0;i<arry.length();i++)
		            {
		
		              Gson gson = new GsonBuilder().create();  
		
		              Map proMap = gson.fromJson(arry.get(i).toString(), HashMap.class);  
		              String licCode = proMap.get("LicenseTypeID_Code");
		              
		              String licNumber = proMap.get("LicenseNumber");
		              String providerId = proMap.get("ProviderID");
		              if (Util.isNotNullOrEmpty(providerId)) 
		              {
		                if(providerInfoMap.containsKey(providerId.trim()))
		                {
		                 
		                  Map outMap =  providerInfoMap.get(providerId.trim());
		                  if(licCode.equalsIgnoreCase("DEA"))
		                  {
		                  	outMap.put("DEANumber",licNumber);
		                  } 
		                  else if(licCode.equalsIgnoreCase("StateProfLicense"))
		                  {
		                  	outMap.put("StateProfLicense",licNumber);
		                  }
		                  providerInfoMap.put(providerId.trim(),outMap);
		                }
					  			}
		              count++;
		            }
		          }//res not null  
		     		}
		       catch(Exception e)
		       {
		         logger.error("Ascension-Rule-MDStaff-Ascension-After - fetchProviderRecords() - Cannot perform MDStaff Account Aggregation. Error fetching MDStaff data from endpoint. Details:\n"+e.getMessage());
		         
		         logger.trace(exception.printStackTrace());
		          
		         statusMessage = "ERROR" ;
		       }
		   	 }
		   	 if(statusMessage.isEmpty()){
		   	 	
		   	 	statusMessage = "SUCCESS" ;
		   	 }
		   	 
						
		} else {
			
			statusMessage = "TOKEN_ERROR" ; 
		}
		
		logger.info("Ascension-Rule-MDStaff-Ascension-After - fetchProviderRecords() - statusMessage - " + statusMessage) ;
		
		logger.trace("Ascension-Rule-MDStaff-Ascension-After - fetchProviderRecords() - End.") ;
		
		return statusMessage ; 
	}	
	
	logger.trace("Ascension-Rule-MDStaff-Ascension-After - Start...") ;
	
	getApplicationDetails() ; 

	for(int currentPageNumber=1;currentPageNumber<=MAX_NUMBER_OF_PAGES;currentPageNumber++){
		
		String statusMessage = fetchProviderRecords(currentPageNumber) ; 
		
		if(	statusMessage.equals("LAST_PAGE") || 
			statusMessage.equals("TOKEN_ERROR") ||
			statusMessage.equals("ERROR")){
			
			break ; 
			
		} 
	}
	
	logger.info("Ascension-Rule-MDStaff-Ascension-After - Total Number of Records Fetched - " + totalNumberOfProvidersFetched) ;
	
	logger.trace("Ascension-Rule-MDStaff-Ascension-After - End.") ;
	
     //Add all the records to the OOTB object
     for(String key : providerInfoMap.keySet())
     {
         processedResponseObject.add(providerInfoMap.get(key));        
     }
